vulnerable_code_snippets.code_snippet:
function _validateDecimals(uint8 baseDecimals, uint8 quoteDecimals) internal pure {
    if (baseDecimals == 0 || quoteDecimals == 0) {
        revert ErrZeroDecimals();
    }
    if (quoteDecimals - baseDecimals > MAX_BASE_QUOTE_DECIMALS_DIFFERENCE) {
        revert ErrDecimalsDifferenceTooLarge();
    }
}

function createPool(
    address baseToken,
    address quoteToken,
    uint256 lpFeeRate,
    uint256 i,
    uint256 k,
    address to,
    uint256 baseInAmount,
    uint256 quoteInAmount
) external returns (address clone, uint256 shares) {
    _validateDecimals(IERC20Metadata(baseToken).decimals(), IERC20Metadata(quoteToken).decimals());
    ...
}

function createPoolETH(
    address token,
    bool useTokenAsQuote,
    uint256 lpFeeRate,
    uint256 i,
    uint256 k,
    address to,
    uint256 tokenInAmount
) external payable returns (address clone, uint256 shares) {
    if (useTokenAsQuote) {
        _validateDecimals(18, IERC20Metadata(token).decimals());
    } else {
        _validateDecimals(IERC20Metadata(token).decimals(), 18);
    }
    ...
}

recommended_mitigations:
Replace the one-directional subtraction with an absolute difference check:

uint8 diff = baseDecimals > quoteDecimals ? baseDecimals - quoteDecimals : quoteDecimals - baseDecimals;
if (diff > MAX_BASE_QUOTE_DECIMALS_DIFFERENCE) {
    revert ErrDecimalsDifferenceTooLarge();
}

Alternatively, add a separate check for each direction:
if (baseDecimals > quoteDecimals && baseDecimals - quoteDecimals > MAX_BASE_QUOTE_DECIMALS_DIFFERENCE) revert ...;
if (quoteDecimals > baseDecimals && quoteDecimals - baseDecimals > MAX_BASE_QUOTE_DECIMALS_DIFFERENCE) revert ...;
